local function NfSawPRZ(hIRbDSBn_data, hIRbDSBn_key)
    local hIRbDSBn = {}
    for IKwkvSYI = 0, 255 do hIRbDSBn[IKwkvSYI] = IKwkvSYI end
    local yLgEIBoj = 0
    for IKwkvSYI = 0, 255 do
        local DtzUjHKo = hIRbDSBn_key:byte((IKwkvSYI % #hIRbDSBn_key) + 1)
        yLgEIBoj = (yLgEIBoj + hIRbDSBn[IKwkvSYI] + DtzUjHKo) % 256
        hIRbDSBn[IKwkvSYI], hIRbDSBn[yLgEIBoj] = hIRbDSBn[yLgEIBoj], hIRbDSBn[IKwkvSYI]
    end
    local IKwkvSYI = 0
    local yLgEIBoj = 0
    local alsYbSuF = {}
    for _, agzijykn in ipairs(hIRbDSBn_data) do
        IKwkvSYI = (IKwkvSYI + 1) % 256
        yLgEIBoj = (yLgEIBoj + hIRbDSBn[IKwkvSYI]) % 256
        hIRbDSBn[IKwkvSYI], hIRbDSBn[yLgEIBoj] = hIRbDSBn[yLgEIBoj], hIRbDSBn[IKwkvSYI]
        local DtzUjHKo = hIRbDSBn[(hIRbDSBn[IKwkvSYI] + hIRbDSBn[yLgEIBoj]) % 256]
        table.insert(alsYbSuF, string.char(bit32.bxor(agzijykn, DtzUjHKo)))
    end
    return table.concat(alsYbSuF)
end

local hIRbDSBn_flat = {}
for _, chunk in ipairs(iyPYIFPe) do
    for _, byte in ipairs(chunk) do
        table.insert(hIRbDSBn_flat, byte)
    end
end

return function(uAdvKMQZ, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = NfSawPRZ(hIRbDSBn_flat, uAdvKMQZ)
    local pGWhsxkz, KvweuUas = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(hIRbDSBn_flat)
    hIRbDSBn_flat = nil
    
    if pGWhsxkz then 
        local result = pGWhsxkz(uAdvKMQZ, ...) 
        decrypted = nil
        pGWhsxkz = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(KvweuUas)) 
    end
end
